+async function createOutputFiles(
+  sandbox: SandboxClient,
+  outputDir: string
+): Promise<Array<{ path: string; bytes: Uint8Array; sha256: string }>> {
+  const normalizedOutputDir = normalizeProjectRoot(outputDir);
+  const output = await runSandboxCommand(
+    sandbox,
+    `cd ${shellQuote(
+      WORKSPACE_ROOT
+    )} && python3 - <<'PY'\n# nimbus_collect_output_files\nimport base64\nimport hashlib\nimport json\nimport os\n\nroot = ${JSON.stringify(normalizedOutputDir)}\nif not os.path.isdir(root):\n    print('__NIMBUS_OUTPUT_DIR_MISSING__')\n    raise SystemExit(0)\nroot_real = os.path.realpath(root)\nfiles = []\nfor dirpath, dirnames, filenames in os.walk(root):\n    dirnames.sort()\n    for dirname in list(dirnames):\n        directory_absolute = os.path.join(dirpath, dirname)\n        directory_rel = os.path.relpath(directory_absolute, root).replace('\\\\', '/')\n        if os.path.islink(directory_absolute):\n            print('__NIMBUS_OUTPUT_DIR_SYMLINK__:' + directory_rel + '/')\n            raise SystemExit(0)\n    filenames.sort()\n    for filename in filenames:\n        absolute = os.path.join(dirpath, filename)\n        rel = os.path.relpath(absolute, root).replace('\\\\', '/')\n        if os.path.islink(absolute):\n            print('__NIMBUS_OUTPUT_DIR_SYMLINK__:' + rel)\n            raise SystemExit(0)\n        resolved = os.path.realpath(absolute)\n        if not (resolved == root_real or resolved.startswith(root_real + os.sep)):\n            print('__NIMBUS_OUTPUT_DIR_ESCAPE__:' + rel)\n            raise SystemExit(0)\n        with open(absolute, 'rb') as f:\n            payload = f.read()\n        files.append({\n            'path': rel,\n            'size': len(payload),\n            'sha256': hashlib.sha256(payload).hexdigest(),\n            'base64': base64.b64encode(payload).decode('ascii'),\n        })\nfiles.sort(key=lambda item: item['path'])\nprint(json.dumps({'files': files}))\nPY`,
+    { timeout: 8 * 60 * 1000 }
+  );
+
+  if (output.trim() === '__NIMBUS_OUTPUT_DIR_MISSING__') {
+    throw new PolicyError('provider_invalid_output_dir', `deploy.outputDir directory does not exist: ${normalizedOutputDir}`);
+  }
+  if (output.trim().startsWith('__NIMBUS_OUTPUT_DIR_SYMLINK__:')) {
+    const path = output.trim().slice('__NIMBUS_OUTPUT_DIR_SYMLINK__:'.length).trim() || 'unknown';
+    throw new PolicyError('provider_invalid_output_dir', `deploy.outputDir contains a symlinked entry: ${path}`);
+  }
+  if (output.trim().startsWith('__NIMBUS_OUTPUT_DIR_ESCAPE__:')) {
+    const path = output.trim().slice('__NIMBUS_OUTPUT_DIR_ESCAPE__:'.length).trim() || 'unknown';
+    throw new PolicyError('provider_invalid_output_dir', `deploy.outputDir contains a file resolving outside output root: ${path}`);
+  }
+
+  const parsed = JSON.parse(output) as { files?: Array<{ path?: string; base64?: string; sha256?: string; size?: number }> };
+  const files = Array.isArray(parsed.files) ? parsed.files : [];
+  if (files.length === 0) {
+    throw new PolicyError('provider_invalid_output_dir', `deploy.outputDir directory does not contain any files: ${normalizedOutputDir}`);
+  }
+
+  return files
+    .map((file) => {
+      const path = typeof file.path === 'string' ? file.path : '';
+      const base64 = typeof file.base64 === 'string' ? file.base64 : '';
+      const sha256 = typeof file.sha256 === 'string' ? file.sha256 : '';
+      if (!path || !base64 || !sha256) {
+        throw new PolicyError('provider_deploy_failed', 'Output file collection returned invalid metadata');
+      }
+      return {
+        path,
+        bytes: fromBase64(base64),
+        sha256,
+      };
+    })
+    .sort((a, b) => a.path.localeCompare(b.path));
+}
